import { prisma } from "@/src/lib/prisma";
import {
    extractWebsiteIntelligence,
    generateAdTabs,
    generateCreativeStrategy,
    type WebsiteIntelligence,
} from "@/src/lib/anthropic";
import {
    normalizeAndValidatePublicUrl,
    scrapeUrlToHtml,
} from "@/src/lib/scrape";
import { extractJsonObject } from "@/src/lib/claudeAds";
import {
    parseValidateAndNormalizeClaudeAds,
    type ClaudeParseDiagnostics,
} from "@/src/lib/claude/parseClaudeJson";
import { redirect } from "next/navigation";

function stripHtml(html: string) {
    return html
        .replace(/<script[\s\S]*?<\/script>/gi, "")
        .replace(/<style[\s\S]*?<\/style>/gi, "")
        .replace(/<[^>]+>/g, " ")
        .replace(/\s+/g, " ")
        .trim();
}

function getErrorMessage(error: unknown) {
    if (error instanceof Error) return error.message;
    if (typeof error === "string") return error;

    try {
        return JSON.stringify(error);
    } catch {
        return "Unknown error";
    }
}

function normalizeAdCount(value: string | null | undefined) {
    const parsed = Number(value);

    if (!Number.isFinite(parsed)) return "6";
    if (parsed < 1) return "1";
    if (parsed > 1000) return "1000";

    return String(Math.floor(parsed));
}

async function createJob(formData: FormData) {
    "use server";

    const urlRaw = formData.get("url")?.toString().trim();
    const campaignType =
        formData.get("campaignType")?.toString().trim() || "product";
    const platform = formData.get("platform")?.toString().trim() || "Meta";
    const funnelStage = formData.get("funnelStage")?.toString().trim() || "Mix";
    const formatRatio =
        formData.get("formatRatio")?.toString().trim() ||
        "70% 9:16 / 30% 1080x1080";
    const primaryAngles =
        formData.get("primaryAngles")?.toString().trim() ||
        "Problem/Solution, Lifestyle, Urgency";
    const testimonialUsage =
        formData.get("testimonialUsage")?.toString().trim() || "Mix";
    const ctaStyle = formData.get("ctaStyle")?.toString().trim() || "Mix";
    const visualStyle = formData.get("visualStyle")?.toString().trim() || "Mix";
    const numberOfAds = normalizeAdCount(
        formData.get("numberOfAds")?.toString().trim()
    );
    const requestedCount = Number(numberOfAds);
    const referenceImageTypes =
        formData.get("referenceImageTypes")?.toString().trim() || "Product only";

    if (!urlRaw) {
        redirect(`/new?error=${encodeURIComponent("URL is required")}`);
    }

    // Important: `job.url` must come only from the submitted input.
    // Do not overwrite it with redirect targets from the scraper.
    let jobUrl = urlRaw;
    let rawText = "";
    let scrapeStatus: string | null = null;
    let scrapedImageUrls: string[] = [];

    try {
        jobUrl = normalizeAndValidatePublicUrl(urlRaw);
    } catch (error) {
        const message = getErrorMessage(error);
        redirect(`/new?error=${encodeURIComponent(message)}`);
    }

    try {
        const scraped = await scrapeUrlToHtml(jobUrl);
        scrapedImageUrls = scraped.imageUrls || [];
        rawText = stripHtml(scraped.html).slice(0, 15000);

        if (!rawText.trim()) {
            scrapeStatus = `scrape_empty_text (status ${scraped.status})`;
        }
    } catch (error) {
        const message = getErrorMessage(error);
        // We still create the job so the user can see the failure reason.
        scrapeStatus = `scrape_error: ${message}`;
        rawText = "";
    }

    let claudeOutput = "";
    let kieResult: string | null = null;
    let status = scrapeStatus ? "scrape_error" : "processed";
    let adTabStageSucceeded = false;
    let stageFailure:
        | {
              stage:
                  | "website_intelligence"
                  | "creative_strategy"
                  | "ad_tab_generation"
                  | "unknown";
              message: string;
          }
        | null = null;
    let currentStage:
        | "website_intelligence"
        | "creative_strategy"
        | "ad_tab_generation"
        | "unknown" = "unknown";

    if (!scrapeStatus) {
        try {
            currentStage = "website_intelligence";
            const intelligenceRaw = await extractWebsiteIntelligence({
                rawText,
                imageUrls: scrapedImageUrls,
                campaignTypeHint:
                    campaignType === "donation" ? "donation" : "product",
            });

            const intelligenceParsed = extractJsonObject(intelligenceRaw);
            const websiteIntelligence: WebsiteIntelligence = {
                campaignType:
                    intelligenceParsed?.campaignType === "donation"
                        ? "donation"
                        : intelligenceParsed?.campaignType === "product"
                            ? "product"
                            : "unknown",
                brandName:
                    typeof intelligenceParsed?.brandName === "string"
                        ? intelligenceParsed.brandName
                        : undefined,
                productName:
                    typeof intelligenceParsed?.productName === "string"
                        ? intelligenceParsed.productName
                        : undefined,
                offer:
                    typeof intelligenceParsed?.offer === "string"
                        ? intelligenceParsed.offer
                        : undefined,
                price:
                    typeof intelligenceParsed?.price === "string"
                        ? intelligenceParsed.price
                        : undefined,
                audience: Array.isArray(intelligenceParsed?.audience)
                    ? intelligenceParsed.audience.filter(
                          (x: unknown) => typeof x === "string"
                      )
                    : undefined,
                keyBenefits: Array.isArray(intelligenceParsed?.keyBenefits)
                    ? intelligenceParsed.keyBenefits.filter(
                          (x: unknown) => typeof x === "string"
                      )
                    : undefined,
                objections: Array.isArray(intelligenceParsed?.objections)
                    ? intelligenceParsed.objections.filter(
                          (x: unknown) => typeof x === "string"
                      )
                    : undefined,
                emotionalDrivers: Array.isArray(intelligenceParsed?.emotionalDrivers)
                    ? intelligenceParsed.emotionalDrivers.filter(
                          (x: unknown) => typeof x === "string"
                      )
                    : undefined,
                proofPoints: Array.isArray(intelligenceParsed?.proofPoints)
                    ? intelligenceParsed.proofPoints.filter(
                          (x: unknown) => typeof x === "string"
                      )
                    : undefined,
                visualAssets:
                    intelligenceParsed?.visualAssets &&
                    typeof intelligenceParsed.visualAssets === "object"
                        ? {
                              imageUrls: Array.isArray(
                                  intelligenceParsed.visualAssets.imageUrls
                              )
                                  ? intelligenceParsed.visualAssets.imageUrls.filter(
                                        (x: unknown) => typeof x === "string"
                                    )
                                  : [],
                              hasHumanLifestyleImages:
                                  Boolean(
                                      intelligenceParsed.visualAssets
                                          .hasHumanLifestyleImages
                                  ),
                              hasProductOnlyImages: Boolean(
                                  intelligenceParsed.visualAssets
                                      .hasProductOnlyImages
                              ),
                          }
                        : undefined,
                sourceSummary:
                    typeof intelligenceParsed?.sourceSummary === "string"
                        ? intelligenceParsed.sourceSummary
                        : rawText.slice(0, 500),
            };

            const effectiveCampaignType: "product" | "donation" =
                websiteIntelligence.campaignType === "donation"
                    ? "donation"
                    : websiteIntelligence.campaignType === "product"
                        ? "product"
                        : campaignType === "donation"
                            ? "donation"
                            : "product";

            currentStage = "creative_strategy";
            const strategyRaw = await generateCreativeStrategy({
                websiteIntelligence,
                campaignType: effectiveCampaignType,
                platform,
                funnelStage,
                primaryAngles,
                testimonialUsage,
                ctaStyle,
                visualStyle,
                referenceImageTypes,
                rawTextForIntentTokens: rawText,
            });

            currentStage = "ad_tab_generation";
            claudeOutput = await generateAdTabs({
                creativeStrategyJson: strategyRaw,
                requestedAdCount: requestedCount,
            });

            adTabStageSucceeded = true;

            kieResult = JSON.stringify(
                {
                    websiteIntelligence,
                    creativeStrategy: strategyRaw,
                },
                null,
                2
            );
        } catch (error) {
            const message = getErrorMessage(error);
            status =
                currentStage === "website_intelligence"
                    ? "website_intelligence_error"
                    : currentStage === "creative_strategy"
                        ? "creative_strategy_error"
                        : currentStage === "ad_tab_generation"
                            ? "ad_tab_generation_error"
                            : "claude_error";

            stageFailure = { stage: currentStage, message };
            claudeOutput = JSON.stringify(
                { ads: [], stage: currentStage, error: message },
                null,
                2
            );
            kieResult = JSON.stringify(
                { stage: currentStage, error: message },
                null,
                2
            );
        }
    } else {
        claudeOutput = JSON.stringify({ ads: [], error: scrapeStatus }, null, 2);
        kieResult = JSON.stringify({ scrapeStatus }, null, 2);
    }

    const job = await prisma.job.create({
        data: {
            url: jobUrl,
            campaignType,
            rawText,
            claudeOutput,
            status,
            kieResult: kieResult ?? null,
            platform,
            funnelStage,
            formatRatio,
            primaryAngles,
            testimonialUsage,
            ctaStyle,
            visualStyle,
            numberOfAds,
            referenceImageTypes,
        },
    });

    if (!adTabStageSucceeded) {
        // Persist scraped reference images for later regeneration.
        if (scrapedImageUrls.length > 0) {
            const unique = Array.from(new Set(scrapedImageUrls)).slice(0, 25);
            await prisma.referenceAsset.createMany({
                data: unique.map((url, index) => ({
                    jobId: job.id,
                    adId: null,
                    filePath: url,
                    originalName: `scraped-image-${index + 1}`,
                    mimeType: null,
                })),
            });
        }

        redirect(
            `/jobs/${job.id}?stageError=1&stage=${encodeURIComponent(
                stageFailure?.stage || "unknown"
            )}`
        );
    }

    const parsedAdsResult = parseValidateAndNormalizeClaudeAds(
        claudeOutput,
        requestedCount
    );
    const diagnostics: ClaudeParseDiagnostics = parsedAdsResult.diagnostics;
    const diagJson = JSON.stringify(diagnostics, null, 2);

    if (!parsedAdsResult.ok) {
        await prisma.job.update({
            where: { id: job.id },
            data: {
                status: "ad_parse_error",
                claudeOutput: `${claudeOutput || ""}

__CLAUDE_PARSE_DIAGNOSTICS__
${diagJson}
__END_CLAUDE_PARSE_DIAGNOSTICS__`,
            },
        });

        redirect(`/jobs/${job.id}?parseError=1`);
    }

    // Save scraped reference images (job-level/shared) for Kie.
    if (scrapedImageUrls.length > 0) {
        const unique = Array.from(new Set(scrapedImageUrls)).slice(0, 25);
        await prisma.referenceAsset.createMany({
            data: unique.map((url, index) => ({
                jobId: job.id,
                adId: null,
                filePath: url,
                originalName: `scraped-image-${index + 1}`,
                mimeType: null,
            })),
        });
    }

    await prisma.ad.createMany({
        data: parsedAdsResult.ads.map((ad, index) => ({
            jobId: job.id,
            adNumber: index + 1,
            title: ad.angle || ad.headline || `Ad ${index + 1}`,
            sourceBlock: JSON.stringify(ad, null, 2),
            editedPrompt: String(ad.visualPrompt || "").trim(),
            status: "ready",
        })),
    });

    const returnedCount =
        typeof diagnostics.returnedAdCount === "number"
            ? diagnostics.returnedAdCount
            : parsedAdsResult.ads.length;
    const finalStatus =
        returnedCount === 0
            ? "ad_parse_error"
            : returnedCount === requestedCount
                ? "success"
                : "processed_with_warnings";

    await prisma.job.update({
        where: { id: job.id },
        data: {
            status: finalStatus,
            claudeOutput: `${claudeOutput || ""}

__CLAUDE_PARSE_DIAGNOSTICS__
${diagJson}
__END_CLAUDE_PARSE_DIAGNOSTICS__`,
        },
    });

    redirect(`/jobs/${job.id}?ad=1`);
}

